    r2new += einsum(v.ovvv, (0, 1, 2, 3), tmp1, (4, 0, 3), (2, 1, 4)) * -1
    del tmp1
    r2new += einsum(v.ovvv, (0, 1, 2, 3), r1, (3,), (1, 2, 0)) * -1
    r2new += einsum(ints.tmp38, (0, 1), r2, (1, 2, 3), (0, 2, 3)) * -2
    r2new += einsum(ints.tmp38, (0, 1), r2, (2, 1, 3), (2, 0, 3)) * -2
    r2new += einsum(ints.tmp35, (0, 1, 2, 3), r2, (3, 0, 4), (2, 1, 4))
    tmp2 = np.copy(np.transpose(r2, (2, 0, 1))) * -1
    tmp2 += np.transpose(r2, (2, 1, 0)) * 2
    r2new += einsum(tmp2, (0, 1, 2), ints.tmp30, (0, 3, 4, 2), (4, 1, 3))
    del tmp2
    tmp3 = einsum(t1, (0, 1), r1, (1,), (0,)) * -1
    tmp3 += einsum(ints.tmp42, (0, 1, 2, 3), r2, (3, 2, 0), (1,))
    r2new += einsum(v.ovov, (0, 1, 2, 3), tmp3, (0,), (3, 1, 2)) * -1
    del tmp3

    return {"r1new": r1new, "r2new": r2new}

